parameters.jsCode:
const bookingBeds = $('Search Booking Beds - Confirmation').all();

function getFirst(value) {
  if (Array.isArray(value)) return value[0];
  return value;
}

const roomIds = [];

for (const item of bookingBeds) {
  const fields = item.json.fields || item.json;

  const status = String(fields['Status'] || '').toLowerCase();
  if (status === 'cancelled' || status === 'canceled') continue;

  const roomId = getFirst(fields['Room ID']);
  if (roomId && !roomIds.includes(roomId)) {
    roomIds.push(roomId);
  }
}

roomIds.sort((a, b) => {
  const na = Number(String(a).replace(/\D/g, '')) || 999;
  const nb = Number(String(b).replace(/\D/g, '')) || 999;
  return na - nb;
});

let assignedRoomSummary = '';

if (roomIds.length === 1) {
  assignedRoomSummary = `Room ${String(roomIds[0]).replace('R', '')}`;
} else if (roomIds.length > 1) {
  assignedRoomSummary =
    'Rooms ' + roomIds.map(id => String(id).replace('R', '')).join(', ');
}

return [
  {
    json: {
      assigned_room_summary: assignedRoomSummary,
      assigned_room_ids: roomIds,
      is_multi_room: roomIds.length > 1,
      assigned_room_count: roomIds.length
    }
  }
];
